#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

string solveEquation(string equation) {
    std::vector<std::string> terms;
    int x = stoi(equation.substr(0, equation.find('=')));
    equation = equation.substr(equation.find('=') + 1);

    std::stringstream ss(equation);
    std::string token;
    while (ss >> token) {
        terms.push_back(token);
    }

    int result = 0;
    int sign = 1;
    for (int i = terms.size() - 1; i >= 0; i--) {
        int num = std::stoi(terms[i]);
        if (terms[i][0] == '-') {
            result *= -1;
            sign *= -1;
        }
        result += num * sign;
        sign *= 2;
    }

    if (result == x) {
        return std::to_string(x) + "=#" + std::to_string(result);
    } else if (result == 0) {
        return "No solution";
    } else {
        return "Infinite solutions";
    }
}
